import React, { useState, useCallback } from 'react';
import { Eye, EyeOff, X } from 'lucide-react';
import { toast } from 'react-toastify';
import api from '../../api/api';
import '../../assets/styles/AuthModal.css';

const AuthModal = ({ isOpen, onClose }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    mobileNo: '',
    email: '',
    address: '',
    password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Toggle between Login and Signup modes
  const toggleMode = useCallback(() => {
    setIsLogin(prev => !prev);
    setError('');
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const endpoint = isLogin ? '/api/auth/login' : '/api/auth/signup';

    try {
      const data = await api.post(endpoint, formData);

      if (isLogin) {
        // Handle successful login
        localStorage.setItem('token', data.token);
        localStorage.setItem('loginTimestamp', Date.now().toString());
        toast.success('Login successful!');
        window.dispatchEvent(new Event('authChange'));
        onClose();
      } else {
        // Handle successful signup
        toast.success('Signup successful! Please Sign In.');
        setIsLogin(true); // Switch to login screen natively
      }
    } catch (err) {
      const msg = err.response?.data?.message || 'Authentication failed.';
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="auth-modal-overlay">
      <div className="auth-modal">
        <button className="auth-close-btn" onClick={onClose} aria-label="Close">
          <X size={24} />
        </button>

        <div className="auth-header">
          <h2>{isLogin ? 'Welcome Back' : 'Create an Account'}</h2>
          <p>{isLogin ? 'Login to continue enjoying Heritage Harvest.' : 'Join us for premium handcrafted jaggery.'}</p>
        </div>

        {error && <div className="auth-error">{error}</div>}

        <form className="auth-form" onSubmit={handleSubmit}>
          {!isLogin && (
            <div className="form-row">
              <div className="form-group">
                <label>Full Name</label>
                <input type="text" name="username" value={formData.username} onChange={handleChange} required={!isLogin} placeholder="Enter your name" />
              </div>
              <div className="form-group">
                <label>Address</label>
                <input type="text" name="address" value={formData.address} onChange={handleChange} required={!isLogin} placeholder="City/State" />
              </div>
            </div>
          )}

          <div className="form-group">
            <label>Email Address</label>
            <input type="email" name="email" value={formData.email} onChange={handleChange} required={!isLogin} placeholder="you@example.com" />
          </div>

          <div className="form-group">
            <label>Mobile Number</label>
            <input type="tel" name="mobileNo" value={formData.mobileNo} onChange={handleChange} required={!isLogin} placeholder="Optional for login if email exists" />
          </div>

          <div className="form-group password-group">
            <label>Password</label>
            <div className="password-input-wrapper">
              <input 
                type={showPassword ? 'text' : 'password'} 
                name="password" 
                value={formData.password} 
                onChange={handleChange} 
                required 
                placeholder="Secure password" 
              />
              <button 
                type="button" 
                className="password-toggle-btn" 
                onClick={() => setShowPassword(!showPassword)}
                aria-label="Toggle Password Visibility"
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
          </div>

          <button type="submit" className="auth-submit-btn" disabled={loading}>
            {loading ? 'Processing...' : (isLogin ? 'Sign In' : 'Register')}
          </button>
        </form>

        <div className="auth-footer">
          {isLogin ? (
            <p>Don't have an account? <span onClick={toggleMode} className="auth-toggle-link">Register</span></p>
          ) : (
            <p>Already have an account? <span onClick={toggleMode} className="auth-toggle-link">Log In</span></p>
          )}
        </div>
      </div>
    </div>
  );
};

export default React.memo(AuthModal);
